mapper.select:
select from biz_d365_default_value
del_flag = '0' AND endpoint_name like concat('%',#{endpointName},'%') AND show_in_ui = #{showInUi} AND status = #{status}
order by default_id

mapper.update:
update biz_d365_default_value
endpoint_label=#{endpointLabel}, extra_params=#{extraParams}, default_value=#{defaultValue}, default_label=#{defaultLabel}, show_in_ui=#{showInUi}, status=#{status}, remark=#{remark}, update_by=#{updateBy}, update_time=sysdate(),
where default_id = #{defaultId}
